const cityId = $('Batch of 5 cities').item.json.id;
const items = $input.item.json.hotels ?? [];

function priceBand(estimate) {
  if (!estimate) return null;
  if (estimate < 80)  return '$';
  if (estimate < 180) return '$$';
  if (estimate < 350) return '$$$';
  return '$$$$';
}

function typeFromBooking(hotelTypeId) {
  const map = {
    204: 'hotel', 203: 'apartment', 208: 'guesthouse',
    216: 'hostel', 219: 'aparthotel', 220: 'villa', 222: 'bnb'
  };
  return map[hotelTypeId] ?? 'hotel';
}

return items.map((h) => ({
  json: {
    booking_id: String(h.hotel_id),
    city_id: cityId,
    name: h.name,
    type: typeFromBooking(h.hoteltype_id),
    star_rating: h.class ?? null,
    review_score: h.review_score ?? null,
    review_count: h.number_of_reviews ?? null,
    price_estimate_eur: h.min_total_price ? Math.round(h.min_total_price) : null,
    price_band: priceBand(h.min_total_price),
    lat: h.location?.latitude ?? null,
    lng: h.location?.longitude ?? null,
    amenities: (h.hotel_facilities ?? []).map(f => String(f).toLowerCase().replace(/\s+/g, '_')),
    affiliate_url_template: h.url ?? null,
    image_primary_url: h.main_photo_url ?? null,
    external_ids: JSON.stringify({ booking: h.hotel_id }),
    last_synced_at: new Date().toISOString(),
    is_active: true
  }
}));
